#include<cstdio>
#include<cstdlib>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define int long long 
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e6+10;long long a[N];
struct fhq{int l,r,siz,val,key;}t[N];int cnt,Rt,T1,T2,T3,T4,T5;
inline int Node(int v){t[++cnt].val=v;t[cnt].siz=1;t[cnt].key=rand();return cnt;}
inline void update(int k){t[k].siz=t[t[k].l].siz+t[t[k].r].siz+1;}
inline void split(int cur,int k,int &x,int &y)
{
	if(!cur){x=y=0;return;}
	if(t[cur].val<=k){x=cur;split(t[cur].r,k,t[cur].r,y);}
	else {y=cur;split(t[cur].l,k,x,t[cur].l);} update(cur);
}
inline int merge(int x,int y)
{
	if(!x||!y)return x|y;
	if(t[x].key<t[y].key)return t[x].r=merge(t[x].r,y),update(x),x;
	else return t[y].l=merge(x,t[y].l),update(y),y;
}
signed main()
{
	srand(19260817);int n=read();rep(1,n,i)a[i]=read();
	int P=read();rep(1,n,i)a[i]-=P;rep(1,n,i)a[i]+=a[i-1];
	Rt=Node(0);long long ans=0;
	rep(1,n,i)
	{
		split(Rt,a[i],T1,T2);ans+=t[T1].siz;
		Rt=merge(merge(T1,Node(a[i])),T2);
	}
	printf("%lld\n",ans);return 0;
}
